import { Form, Button, Badge, CloseButton, useState } from "../../cdn";
import type { ChangeEvent } from "../../cdn";
import "./CheckBox.css";

export const CheckBox = ({
  checkState,
  label,
}: {
  checkState: [boolean, (value: boolean) => void];
  label: string;
}) => {
  const [isApplied, setIsApplied] = checkState;

  return (
    <Form>
      <Form.Check
        type="switch"
        onChange={(e: ChangeEvent) => setIsApplied((e.target as HTMLInputElement).checked)}
        checked={isApplied}
      />
      <p>{label}</p>
    </Form>
  );
};

export const CheckBoxText = ({
  checkState,
  labelBefore,
  labelAfter,
  maxWidth = "3rem",
  textState,
}: {
  checkState: [boolean, (value: boolean) => void];
  labelBefore: string;
  labelAfter?: string;
  maxWidth: string;
  textState: [string, (value: string) => void];
}) => {
  const [isApplied, setIsApplied] = checkState;
  const [textValue, setTextValue] = textState;
  const onChangeText = (e: ChangeEvent) => {
    setTextValue((e.target as HTMLInputElement).value);
    setIsApplied(false);
  };
  const onKeyDown = (event: KeyboardEvent) => {
    if (event.key === "Enter") {
      setIsApplied(true);
      event.preventDefault();
    } else {
      setIsApplied(false);
    }
  };

  return (
    <Form>
      <Form.Check
        type="switch"
        onChange={(e: ChangeEvent) => setIsApplied((e.target as HTMLInputElement).checked)}
        checked={isApplied}
      />
      <p>{labelBefore}</p>
      <Form.Control
        value={textValue}
        onChange={onChangeText}
        style={{ maxWidth: maxWidth }}
        onKeyDown={onKeyDown}
      />
      {labelAfter && <p>{labelAfter}</p>}
    </Form>
  );
};

export const SearchBox = ({
  label,
  maxWidth = "3rem",
  addrState,
  priceState,
  agencyState,
}: {
  label: string;
  maxWidth: string;
  addrState: [string, (value: string) => void];
  priceState: [string, (value: string) => void];
  agencyState: [string, (value: string) => void];
}) => {
  const [tmpValue, setTmpValue]: [string, (value: string) => void] = useState("");
  const [addrValue, setAddrValue] = addrState;
  const [priceValue, setPriceValue] = priceState;
  const [agencyValue, setAgencyValue] = agencyState;

  const onClickBtn_AD = () => setAddrValue(tmpValue.trim());
  const onClickBadge_AD = () => setAddrValue("");
  const onClickBtn_P = () => setPriceValue(tmpValue.trim());
  const onClickBadge_P = () => setPriceValue("");
  const onClickBtn_AG = () => setAgencyValue(tmpValue.trim());
  const onClickBadge_AG = () => setAgencyValue("");
  const onChangeText = (e: ChangeEvent) => {
    setTmpValue((e.target as HTMLInputElement).value);
  };
  const onKeyDown = (event: KeyboardEvent) => {
    if (event.key === "Enter") {
      event.preventDefault();
    }
  };

  return (
    <>
      <Form>
        <p>{label}</p>
        <Form.Control
          value={tmpValue}
          onChange={onChangeText}
          style={{ maxWidth: maxWidth }}
          onKeyDown={onKeyDown}
        />
      </Form>

      <Button variant="primary" onClick={onClickBtn_AD} className="x-btn-search">
        Address
      </Button>
      <Button variant="info" onClick={onClickBtn_P} className="x-btn-search">
        Price
      </Button>
      <Button variant="light" onClick={onClickBtn_AG} className="x-btn-search">
        Agency
      </Button>

      <br />

      {addrValue && (
        <Badge pill bg="primary">
          <CloseButton onClick={onClickBadge_AD} />
          <span>{addrValue}</span>
        </Badge>
      )}
      {priceValue && (
        <Badge pill bg="info" text="dark">
          <CloseButton onClick={onClickBadge_P} />
          <span>{priceValue}</span>
        </Badge>
      )}
      {agencyValue && (
        <Badge pill bg="light" text="dark">
          <CloseButton onClick={onClickBadge_AG} />
          <span>{agencyValue}</span>
        </Badge>
      )}
    </>
  );
};
